"""Script de ejecución del experimento federado.Este archivo está pensado para lanzarse directamente desde Spydero desde una terminal, actuando como punto de entrada del proyecto."""from pathlib import Pathimport sysimport logging# ============================================================# AJUSTE DEL PATH PARA SPYDER# ============================================================PROJECT_ROOT = Path.cwd().resolve().parentSRC_DIR = PROJECT_ROOT / "src"if str(SRC_DIR) not in sys.path:    sys.path.insert(0, str(SRC_DIR))# ============================================================# IMPORTS DEL PROYECTO# ============================================================from federated_skin.config.paths import (    METADATA_PATH,    IMAGES_DIR,    FEATURES_CACHE_PATH,    FINAL_MODEL_PATH,    BEST_BAL_MODEL_PATH,    BEST_F1_MODEL_PATH,    HISTORY_PATH,    PLOT_PATH,    CONFUSION_PATH,    REPORT_PATH,    create_directories,    check_input_paths,)from federated_skin.config.settings import get_default_configfrom federated_skin.data.dataset_builder import FeatureDatasetBuilderfrom federated_skin.data.splits import df_to_xyfrom federated_skin.federation.experiment import FederatedExperimentfrom federated_skin.reporting.reports import (    save_history,    plot_history,    plot_confusion_matrix,    build_classification_report_text,    save_text_report,    print_final_summary,)from federated_skin.vision.pipeline import VisionPipeline# ============================================================# LOGGING# ============================================================logging.basicConfig(level=logging.INFO, format="%(levelname)s | %(message)s")LOGGER = logging.getLogger("federated_simulation")# ============================================================# EJECUCIÓN# ============================================================create_directories()check_input_paths()config = get_default_config()builder = FeatureDatasetBuilder(    metadata_path=METADATA_PATH,    images_dir=IMAGES_DIR,    vision=VisionPipeline(),    logger=LOGGER,)df_features = builder.build_or_load(FEATURES_CACHE_PATH)if df_features.empty:    raise RuntimeError("No se pudieron extraer features válidas.")LOGGER.info("Dataset de features disponible: %d imágenes válidas", len(df_features))LOGGER.info("Distribución por clase:\n%s", df_features["dx"].value_counts())experiment = FederatedExperiment(    df_features=df_features,    config=config,    logger=LOGGER,)result = experiment.run()# Guardado de modelosresult.final_model.save(FINAL_MODEL_PATH)result.best_balanced_model.save(BEST_BAL_MODEL_PATH)result.best_macro_f1_model.save(BEST_F1_MODEL_PATH)# Guardado de histórico y figurasave_history(result.history_df, HISTORY_PATH)plot_history(result.history_df, PLOT_PATH, show=True)# Evaluación detallada del mejor modelo por balanced accuracyX_test, y_test = df_to_xy(result.test_df)best_details = result.best_balanced_model.classification_details(X_test, y_test)report_text = build_classification_report_text(    y_true=best_details["y_true"],    y_pred=best_details["y_pred"],    labels=best_details["labels"],)save_text_report(report_text, REPORT_PATH)plot_confusion_matrix(    cm=best_details["confusion_matrix"],    labels=best_details["labels"],    plot_path=CONFUSION_PATH,    show=True,)# Métricas finalesfinal_metrics = result.final_model.evaluate(X_test, y_test)best_bal_metrics = result.best_balanced_model.evaluate(X_test, y_test)best_f1_metrics = result.best_macro_f1_model.evaluate(X_test, y_test)LOGGER.info("Modelo final guardado en: %s", FINAL_MODEL_PATH)LOGGER.info("Mejor modelo por balanced_accuracy guardado en: %s", BEST_BAL_MODEL_PATH)LOGGER.info("Mejor modelo por macro_f1 guardado en: %s", BEST_F1_MODEL_PATH)LOGGER.info("Histórico guardado en: %s", HISTORY_PATH)LOGGER.info("Gráfica guardada en: %s", PLOT_PATH)LOGGER.info("Classification report guardado en: %s", REPORT_PATH)LOGGER.info("Matriz de confusión guardada en: %s", CONFUSION_PATH)print_final_summary(    history_df=result.history_df,    best_balanced_round=result.best_balanced_round,    best_macro_f1_round=result.best_macro_f1_round,    final_metrics=final_metrics,    best_bal_metrics=best_bal_metrics,    best_f1_metrics=best_f1_metrics,    report_text=report_text,    tail_rows=10,)